INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (2, 10046, 24, "2020/07/31 12:00:00", 24001, 0.0, 0.0, 2, "アヤネ", 102301, "2030/12/17 14:59:59", 401, "やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (1, 10046, 24, "2020/07/31 12:00:00", 24002, 0.0, 2.21, 2, "アヤネ", 102301, "2030/12/17 14:59:59", 402, "私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (2, 10046, 24, "2020/07/31 12:00:00", 24003, 0.0, 0.0, 2, "アヤネ", 102301, "2030/12/17 14:59:59", 403, "やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (2, 10046, 24, "2020/07/31 12:00:00", 24004, 0.0, 1.99, 1, "アサヒ", 192201, "2030/12/17 14:59:59", 701, "特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (1, 10046, 24, "2020/07/31 12:00:00", 24005, 0.0, 2.21, 2, "アサヒ", 192201, "2030/12/17 14:59:59", 702, "よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (2, 10046, 24, "2020/07/31 12:00:00", 24006, 0.0, 3.33, 1, "アサヒ", 192201, "2030/12/17 14:59:59", 703, "試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (2, 10046, 24, "2020/07/31 12:00:00", 24007, 0.0, 0.0, 2, "部員３", 192301, "2030/12/17 14:59:59", 801, "このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (1, 10046, 24, "2020/07/31 12:00:00", 24008, 0.0, 2.68, 2, "部員３", 192301, "2030/12/17 14:59:59", 802, "オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (2, 10046, 24, "2020/07/31 12:00:00", 24009, 0.0, 0.0, 2, "部員３", 192301, "2030/12/17 14:59:59", 803, "いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (1, 10046, 24, "2020/07/31 12:00:00", 24010, 0.0, 0.0, 1, "", 192501, "2030/12/17 14:59:59", 501, "やった！", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (1, 10046, 24, "2020/07/31 12:00:00", 24011, 0.0, 0.0, 1, "", 192501, "2030/12/17 14:59:59", 502, "勝ったよ！", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (1, 10046, 24, "2020/07/31 12:00:00", 24012, 0.0, 0.0, 1, "", 192501, "2030/12/17 14:59:59", 503, "いい調子！", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (6, 10046, 24, "2020/07/31 12:00:00", 24013, 0.0, 5.33, 2, "ミサト", 113501, "2030/12/17 14:59:59", 111, "あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (1, 10046, 24, "2020/07/31 12:00:00", 24014, 0.0, 6.85, 2, "ミサト", 113501, "2030/12/17 14:59:59", 112, "みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (1, 10046, 24, "2020/07/31 12:00:00", 24015, 0.0, 3.0, 2, "ミサト", 113501, "2030/12/17 14:59:59", 113, "練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (1, 10046, 24, "2020/07/31 12:00:00", 24016, 0.0, 6.11, 2, "ダイチ", 192401, "2030/12/17 14:59:59", 611, "まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (1, 10046, 24, "2020/07/31 12:00:00", 24017, 0.0, 6.75, 2, "ダイチ", 192401, "2030/12/17 14:59:59", 612, "ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (2, 10046, 24, "2020/07/31 12:00:00", 24018, 0.0, 0.0, 2, "ダイチ", 192401, "2030/12/17 14:59:59", 613, "おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (2, 10046, 24, "2020/07/31 12:00:00", 24019, 0.0, 4.52, 1, "ハツネ", 113401, "2030/12/17 14:59:59", 211, "きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (2, 10046, 24, "2020/07/31 12:00:00", 24020, 0.0, 3.89, 1, "ハツネ", 113401, "2030/12/17 14:59:59", 212, "やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (1, 10046, 24, "2020/07/31 12:00:00", 24021, 0.0, 13.49, 2, "ハツネ", 113401, "2030/12/17 14:59:59", 213, "よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (1, 10046, 24, "2020/07/31 12:00:00", 24022, 0.0, 3.17, 2, "カヤ", 106501, "2030/12/17 14:59:59", 311, "いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (1, 10046, 24, "2020/07/31 12:00:00", 24023, 0.0, 4.42, 2, "カヤ", 106501, "2030/12/17 14:59:59", 312, "どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (6, 10046, 24, "2020/07/31 12:00:00", 24024, 0.0, 2.89, 1, "カヤ", 106501, "2030/12/17 14:59:59", 313, "なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (4, 10046, 24, "2020/07/31 12:00:00", 24025, 0.0, 3.71, 3, "アヤネ", 102301, "2030/12/17 14:59:59", 421, "あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (2, 10046, 24, "2020/07/31 12:00:00", 24026, 0.0, 5.1, 1, "アサヒ", 192201, "2030/12/17 14:59:59", 721, "いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (1, 10046, 24, "2020/07/31 12:00:00", 24027, 0.0, 4.34, 3, "部員３", 192301, "2030/12/17 14:59:59", 821, "ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (1, 10046, 24, "2020/07/31 12:00:00", 24028, 0.0, 0.0, 1, "", 192501, "2030/12/17 14:59:59", 521, "いい勝負だったよ\nまたやろうね", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (1, 10046, 24, "2020/07/31 12:00:00", 24029, -360.0, 5.62, 2, "ミサト", 113501, "2030/12/17 14:59:59", 101, "とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (1, 10046, 24, "2020/07/31 12:00:00", 24030, -360.0, 9.58, 2, "ミサト", 113501, "2030/12/17 14:59:59", 102, "頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (2, 10046, 24, "2020/07/31 12:00:00", 24031, -360.0, 0.0, 2, "ミサト", 113501, "2030/12/17 14:59:59", 103, "いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (2, 10046, 24, "2020/07/31 12:00:00", 24032, -360.0, 9.13, 1, "ミサト", 113501, "2030/12/17 14:59:59", 104, "夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (1, 10046, 24, "2020/07/31 12:00:00", 24033, -360.0, 8.27, 2, "ミサト", 113501, "2030/12/17 14:59:59", 105, "絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！", 0.0);
